2123: bool ConnectionManagerImpl::ActiveStream::shouldSkipDeferredCloseDelay() const {
2124:   // If HTTP/1.0 has no content length, it is framed by close and won't consider
2125:   // the request complete until the FIN is read. Don't delay close in this case.
2126:   const bool http_10_sans_cl = (connection_manager_.codec_->protocol() == Protocol::Http10) &&
2127:                                (!response_headers_ || !response_headers_->ContentLength());
2128:   // We also don't delay-close in the case of HTTP/1.1 where the request is
2129:   // fully read, as there's no race condition to avoid.
2130:   const bool connection_close = filter_manager_.streamInfo().shouldDrainConnectionUponCompletion();
2131:   const bool request_complete = filter_manager_.hasLastDownstreamByteReceived();
2132: 
2133:   // Don't do delay close for HTTP/1.0 or if the request is complete.
2134:   return connection_close && (request_complete || http_10_sans_cl);
2135: }
